import{_ as t,o as e,c as r,a0 as s}from"./chunks/framework.jwovEGr5.js";const n="/assets/dash-3.Bmn4-Nry.png",m=JSON.parse('{"title":"⚖️ 全服市場行情與均價走勢","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Market-Analytics.md","filePath":"Web-Market-Analytics.md"}'),o={name:"Web-Market-Analytics.md"};function l(i,a,c,_,d,p){return e(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="⚖️-全服市場行情與均價走勢" tabindex="-1">⚖️ 全服市場行情與均價走勢 <a class="header-anchor" href="#⚖️-全服市場行情與均價走勢" aria-label="Permalink to &quot;⚖️ 全服市場行情與均價走勢&quot;">​</a></h1><p>本伺服器設有大數據市場分析系統，收集每一次的玩家交易，並在網頁端提供實時行情展示。</p><p><img src="'+n+'" alt="全服市場行情走勢"></p><hr><h2 id="📈-1-今日成交均價與趨勢" tabindex="-1">📈 1. 今日成交均價與趨勢 <a class="header-anchor" href="#📈-1-今日成交均價與趨勢" aria-label="Permalink to &quot;📈 1. 今日成交均價與趨勢&quot;">​</a></h2><p>在 <strong>「市場行情」</strong> 面板中，系統會自動統計每種物品的交易價格：</p><ul><li><strong>今日均價</strong>：根據今日全服成交的所有紀錄，計算出該物品的平均交易價格，防止物價惡性通貨膨脹。</li><li><strong>7日物價走勢圖</strong>：展示過去 7 天內，特定熱門物資（如鑽石、鐵錠、黃金）的成交價格走勢，提供精確的商業投資參考。</li></ul><hr><h2 id="♻️-2-全服回收機制與限額" tabindex="-1">♻️ 2. 全服回收機制與限額 <a class="header-anchor" href="#♻️-2-全服回收機制與限額" aria-label="Permalink to &quot;♻️ 2. 全服回收機制與限額&quot;">​</a></h2><p>為維護基礎物價，伺服器提供官方回收管道：</p><ul><li><strong>每日回收限額</strong>：每位玩家每日出售給系統商店的金額設有上限，額度於每日凌晨 0:00 重設。</li><li><strong>動態價格保護</strong>：如果全服短時間內大量拋售同一種物品，系統回收價格會自動微幅調降；反之若缺乏該物品，回收價會調高。</li></ul>',11)])])}const u=t(o,[["render",l]]);export{m as __pageData,u as default};
